import{_ as a}from"./chunks/微笑狼的公开仓库.gGdYP2E_.js";import{_ as e,o as n,c as i,a2 as c}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Auto Tagging","description":"","frontmatter":{},"headers":[],"relativePath":"vi-VN/Other/auto-tagging.md","filePath":"vi-VN/Other/auto-tagging.md","lastUpdated":1781962217000}'),o={name:"vi-VN/Other/auto-tagging.md"};function s(g,t,d,h,l,p){return n(),i("div",null,[...t[0]||(t[0]=[c('<h1 id="auto-tagging" tabindex="-1">Auto Tagging <a class="header-anchor" href="#auto-tagging" aria-label="Permalink to &quot;Auto Tagging&quot;">​</a></h1><p>Auto tagging được cấu hình tại:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Auto Tagging</span></span></code></pre></div><p>Tính năng này tự động tạo image tags, hữu ích cho search, random image filtering, public gallery filtering và age-rating access control.</p><h2 id="auto-tagging-lam-đuoc-gi" tabindex="-1">Auto Tagging làm được gì <a class="header-anchor" href="#auto-tagging-lam-đuoc-gi" aria-label="Permalink to &quot;Auto Tagging làm được gì&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>Generate content tags</td><td>Thêm tags cho people, scenes, objects, art style và visual content tương tự.</td></tr><tr><td>Generate character tags</td><td>Hữu ích cho anime images và illustrations.</td></tr><tr><td>Add orientation tags</td><td>Thêm <code>landscape</code>, <code>portrait</code> hoặc <code>square</code>.</td></tr><tr><td>Add image rating</td><td>Lưu kết quả rating <code>G/S/Q/E</code> cho general, sensitive, questionable hoặc explicit content.</td></tr><tr><td>Auto-tag on upload</td><td>Newly uploaded images tự động đi vào tagging flow.</td></tr><tr><td>Batch tagging</td><td>Thêm tags cho old images trong tất cả folders hoặc selected folders.</td></tr></tbody></table><h2 id="can-chuan-bi-truoc" tabindex="-1">Cần chuẩn bị trước <a class="header-anchor" href="#can-chuan-bi-truoc" aria-label="Permalink to &quot;Cần chuẩn bị trước&quot;">​</a></h2><p>Chuẩn bị ít nhất một Hugging Face Space URL có thể truy cập.</p><p>Cách recommended là duplicate Space <code>wd-tagger</code> của SmilingWolf vào Hugging Face account của bạn:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><p>Bạn có thể tạm dùng public Space, nhưng public Spaces được nhiều users dùng chung nên có thể queue, chậm hoặc unavailable. Space duplicate dưới account của bạn ổn định hơn cho auto tagging dài hạn.</p><h2 id="duplicate-space-cua-smilingwolf" tabindex="-1">Duplicate Space của SmilingWolf <a class="header-anchor" href="#duplicate-space-cua-smilingwolf" aria-label="Permalink to &quot;Duplicate Space của SmilingWolf&quot;">​</a></h2><ol><li>Sign in vào Hugging Face.</li><li>Mở <code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code>.</li></ol><p><img src="'+a+`" alt="SmilingWolf public Space" loading="lazy"></p><ol start="3"><li>Nhấn menu ba chấm ở góc trên bên phải.</li><li>Chọn <code>Duplicate this Space</code>.</li><li>Giữ Space name mặc định hoặc chọn tên riêng, ví dụ <code>wd-tagger</code>.</li><li>Đặt visibility là <code>Public</code>. Public Spaces dễ để ImgBed call hơn.</li><li>Ban đầu giữ default free hardware. Chỉ upgrade sau nếu queueing rõ rệt.</li><li>Create Space và chờ build xong.</li></ol><p>Sau khi build xong, mở Space page của bạn. URL thường có dạng:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/your-name/wd-tagger</span></span></code></pre></div><p>Copy browser URL và paste vào <code>Space URLs</code> của ImgBed.</p><h2 id="đien-nhieu-space-urls" tabindex="-1">Điền nhiều Space URLs <a class="header-anchor" href="#đien-nhieu-space-urls" aria-label="Permalink to &quot;Điền nhiều Space URLs&quot;">​</a></h2><p>Mỗi dòng nhập một Space URL.</p><p>Examples:</p><table tabindex="0"><thead><tr><th>Value</th><th>Description</th></tr></thead><tbody><tr><td><code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code></td><td>SmilingWolf public Space. Phù hợp để test tạm thời.</td></tr><tr><td><code>https://huggingface.co/spaces/lintonxue00/wd-tagger</code></td><td>Copied Space page URL.</td></tr><tr><td><code>https://huggingface.co/spaces/your-name/wd-tagger</code></td><td>Space bạn tự duplicate.</td></tr></tbody></table><p>Bạn có thể nhập nhiều URLs. ImgBed dùng nhiều Spaces cùng lúc, giúp cải thiện speed.</p><p>Nếu một Space temporarily unavailable, các Space khác vẫn có thể tiếp tục processing.</p><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Recommendation</th></tr></thead><tbody><tr><td><code>Space URLs</code></td><td>Nhập Space URLs đã chuẩn bị. Cần ít nhất một URL.</td></tr><tr><td>Target folder</td><td>Để trống cho tất cả folders. Chỉ chọn folder khi muốn process một directory cụ thể.</td></tr><tr><td>Recognition model</td><td>Giữ mặc định <code>wd-swinv2-tagger-v3</code>.</td></tr><tr><td>General tag threshold</td><td>Default phù hợp với hầu hết images. Giá trị thấp tạo nhiều tags hơn; giá trị cao tạo ít tags hơn.</td></tr><tr><td>Character tag threshold</td><td>Default khá thận trọng và giúp tránh character tags sai.</td></tr><tr><td><code>MCut</code> automatic threshold</td><td>Ban đầu để off. Bật khi muốn model tự quyết định số lượng tags.</td></tr><tr><td>Auto-tag on upload</td><td>Bật nếu muốn newly uploaded images tự động có tags.</td></tr><tr><td>Start tagging</td><td>Batch-tag old images thủ công.</td></tr></tbody></table><h2 id="recommended-starting-values" tabindex="-1">Recommended Starting Values <a class="header-anchor" href="#recommended-starting-values" aria-label="Permalink to &quot;Recommended Starting Values&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Recommended Value</th></tr></thead><tbody><tr><td>Recognition model</td><td><code>wd-swinv2-tagger-v3</code></td></tr><tr><td>General tag threshold</td><td><code>0.35</code></td></tr><tr><td>Character tag threshold</td><td><code>0.85</code></td></tr><tr><td><code>MCut</code></td><td>Ban đầu Off</td></tr><tr><td>Auto-tag on upload</td><td>Enable nếu cần</td></tr></tbody></table><p>Nếu tags quá nhiều, tăng nhẹ general threshold.</p><p>Nếu tags quá ít, giảm nhẹ general threshold.</p><h2 id="batch-tagging" tabindex="-1">Batch Tagging <a class="header-anchor" href="#batch-tagging" aria-label="Permalink to &quot;Batch Tagging&quot;">​</a></h2><ol><li>Điền <code>Space URLs</code>.</li><li>Chọn target folder.</li><li>Nhấn start tagging.</li><li>Chờ progress hoàn tất.</li></ol><p>Nếu target folder trống, ImgBed process tất cả folders.</p><p>Batch tagging phù hợp với old images. Với new images, enable auto-tag on upload để không cần chạy thủ công mỗi lần.</p><h2 id="auto-tag-on-upload" tabindex="-1">Auto-Tag on Upload <a class="header-anchor" href="#auto-tag-on-upload" aria-label="Permalink to &quot;Auto-Tag on Upload&quot;">​</a></h2><p>Sau khi auto-tag on upload được bật, newly uploaded images tự động call <code>Space URLs</code> đã cấu hình.</p><p>Phù hợp cho sử dụng lâu dài.</p><p>Nếu Space đang queue, upload vẫn có thể hoàn tất trước và tagging tiếp tục sau đó.</p><h2 id="images-nao-đuoc-process" tabindex="-1">Images nào được process <a class="header-anchor" href="#images-nao-đuoc-process" aria-label="Permalink to &quot;Images nào được process&quot;">​</a></h2><p>Auto tagging chủ yếu process image files.</p><p>Images đã có đủ tags, orientation, rating, width và height sẽ bị skip để tránh Space calls không cần thiết.</p><p>ImgBed chỉ điền thông tin còn thiếu khi có thể. Ví dụ, nếu chỉ thiếu orientation, nó sẽ cố thêm orientation mà không gọi full content tag flow.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="vi-sao-nen-duplicate-space-rieng" tabindex="-1">Vì sao nên duplicate Space riêng? <a class="header-anchor" href="#vi-sao-nen-duplicate-space-rieng" aria-label="Permalink to &quot;Vì sao nên duplicate Space riêng?&quot;">​</a></h3><p>Public Spaces được nhiều users dùng chung. Space duplicate của bạn chủ yếu phục vụ ImgBed site của bạn nên thường nhanh và đáng tin cậy hơn.</p><h3 id="space-lien-tuc-starting-up" tabindex="-1">Space liên tục Starting Up <a class="header-anchor" href="#space-lien-tuc-starting-up" aria-label="Permalink to &quot;Space liên tục Starting Up&quot;">​</a></h3><p>Sau lần tạo đầu tiên, hoặc sau thời gian idle dài, Space có thể cần thời gian để start.</p><p>Hãy mở Space page trước. Khi nó nhận diện image bình thường, quay lại ImgBed và start tagging.</p><h3 id="copy-space-url-the-nao" tabindex="-1">Copy Space URL thế nào? <a class="header-anchor" href="#copy-space-url-the-nao" aria-label="Permalink to &quot;Copy Space URL thế nào?&quot;">​</a></h3><p>Mở Hugging Face Space page của bạn và copy browser address.</p><p>Examples:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/lintonxue00/wd-tagger</span></span>
<span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><h3 id="co-the-them-nhieu-spaces-khong" tabindex="-1">Có thể thêm nhiều Spaces không? <a class="header-anchor" href="#co-the-them-nhieu-spaces-khong" aria-label="Permalink to &quot;Có thể thêm nhiều Spaces không?&quot;">​</a></h3><p>Có. Nhập một Space URL mỗi dòng.</p><p>Multiple Spaces process images cùng nhau và hữu ích khi có nhiều images.</p><h3 id="vi-sao-tags-bang-english" tabindex="-1">Vì sao Tags bằng English? <a class="header-anchor" href="#vi-sao-tags-bang-english" aria-label="Permalink to &quot;Vì sao Tags bằng English?&quot;">​</a></h3><p>SmilingWolf models output English tags. Đây là behavior bình thường.</p><p>Tags chủ yếu dùng cho search, filtering, random image API và public gallery filters.</p><h3 id="rating-tags-dung-đe-lam-gi" tabindex="-1">Rating Tags dùng để làm gì? <a class="header-anchor" href="#rating-tags-dung-đe-lam-gi" aria-label="Permalink to &quot;Rating Tags dùng để làm gì?&quot;">​</a></h3><p>Rating results làm việc cùng access mode trong Security Settings.</p><p>Ví dụ, khi visitor access bị giới hạn theo age rating, public browsing và random image features sẽ filter images theo các rules đó.</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Sign in vào Hugging Face</span></span>
<span class="line"><span>-&gt; Mở SmilingWolf/wd-tagger</span></span>
<span class="line"><span>-&gt; Duplicate this Space</span></span>
<span class="line"><span>-&gt; Chờ Space build xong</span></span>
<span class="line"><span>-&gt; Copy Space URL của bạn</span></span>
<span class="line"><span>-&gt; Điền Space URLs trong ImgBed</span></span>
<span class="line"><span>-&gt; Chọn model và thresholds</span></span>
<span class="line"><span>-&gt; Start tagging hoặc enable auto-tag on upload</span></span></code></pre></div>`,63)])])}const b=e(o,[["render",s]]);export{m as __pageData,b as default};
